findings.recommendation:
Add validation for `oc_version` in the Lambda handler:

```python
VALID_OC_VERSIONS = {'4.14', '4.15', '4.16', '4.17', '4.18', '4.19', '4.20'}
if oc_version not in VALID_OC_VERSIONS:
    return response(400, {'error': f'Invalid oc_version: must be one of {sorted(VALID_OC_VERSIONS)}'})
```

Add a filesystem policy that enforces IAM authentication and access-point-only access:

```hcl
resource "aws_efs_file_system_policy" "sre_home" {
  file_system_id = aws_efs_file_system.sre_home.id
  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect    = "Allow"
        Principal = { AWS = "*" }
        Action    = ["elasticfilesystem:ClientMount", "elasticfilesystem:ClientWrite"]
        Resource  = aws_efs_file_system.sre_home.arn
        Condition = {
          Bool = { "elasticfilesystem:AccessedViaMountTarget" = "true" }
          StringEquals = {
            "elasticfilesystem:AccessPointArn" = "arn:aws:elasticfilesystem:*:*:access-point/*"
          }
        }
      },
      {
        Effect    = "Deny"
        Principal = { AWS = "*" }
        Action    = "elasticfilesystem:*"
        Resource  = aws_efs_file_system.sre_home.arn
        Condition = { Bool = { "elasticfilesystem:AccessedViaMountTarget" = "false" } }
      }
    ]
  })
}
```

Add a bucket policy requiring TLS:

```hcl
resource "aws_s3_bucket_policy" "audit" {
  bucket = aws_s3_bucket.audit.id
  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [{
      Sid       = "DenyNonTLS"
      Effect    = "Deny"
      Principal = "*"
      Action    = "s3:*"
      Resource  = [
        "${aws_s3_bucket.audit.arn}",
        "${aws_s3_bucket.audit.arn}/*"
      ]
      Condition = {
        Bool = { "aws:SecureTransport" = "false" }
      }
    }]
  })
}
```

Add source conditions to all ECS and Lambda trust policies:

```hcl
Condition = {
  StringEquals = {
    "aws:SourceAccount" = data.aws_caller_identity.current.account_id
  }
  ArnLike = {
    "aws:SourceArn" = "arn:aws:ecs:${data.aws_region.current.name}:${data.aws_caller_identity.current.account_id}:*"
  }
}
```

Add CloudTrail with S3 data events and management events to the Terraform deployment:

```hcl
resource "aws_cloudtrail" "main" {
  name                          = "${var.project}-${var.stage}-trail"
  s3_bucket_name                = aws_s3_bucket.audit.id
  include_global_service_events = true
  is_multi_region_trail         = true
  enable_log_file_validation    = true
  kms_key_id                    = aws_kms_key.exec_session.arn

  event_selector {
    read_write_type           = "All"
    include_management_events = true
    data_resource {
      type   = "AWS::S3::Object"
      values = ["${aws_s3_bucket.audit.arn}/"]
    }
  }
}
```

Also add `aws_guardduty_detector` and consider `aws_securityhub_account` for FedRAMP compliance aggregation.
